function createSource(
  overrides: Partial<Record<string, unknown>> = {},
): {
  _analysisController?: AbortController;
  _analysisRequestId: number;
  _analyzer?: {
    registry: {
      notifyWorkspaceReady: ReturnType<typeof vi.fn>;
    };
  };
  _analyzerInitialized: boolean;
  _analyzerInitPromise?: Promise<void>;
  _filterPatterns: string[];
  _disabledPlugins: Set<string>;
  _graphData: IGraphData;
  _rawGraphData: IGraphData;
  _firstAnalysis: boolean;
  _resolveFirstWorkspaceReady?: ReturnType<typeof vi.fn>;
  _sendMessage: ReturnType<typeof vi.fn>;
  _sendDepthState: ReturnType<typeof vi.fn>;
  _computeMergedGroups: ReturnType<typeof vi.fn>;
  _sendGroupsUpdated: ReturnType<typeof vi.fn>;
  _updateViewContext: ReturnType<typeof vi.fn>;
  _applyViewTransform: ReturnType<typeof vi.fn>;
  _sendPluginStatuses: ReturnType<typeof vi.fn>;
  _sendDecorations: ReturnType<typeof vi.fn>;
  _sendContextMenuItems: ReturnType<typeof vi.fn>;
  _analyzeAndSendData?: () => Promise<void>;
  _doAnalyzeAndSendData?: (signal: AbortSignal, requestId: number) => Promise<void>;
  _markWorkspaceReady?: (graph: IGraphData) => void;
  _isAnalysisStale?: (signal: AbortSignal, requestId: number) => boolean;
  _isAbortError?: (error: unknown) => boolean;
  [key: string]: unknown;
} {
  return {
    _analysisController: undefined,
    _analysisRequestId: 7,
      _analyzer: {
        registry: {
          notifyWorkspaceReady: vi.fn(),
        },
      },
    _analyzerInitialized: false,
    _analyzerInitPromise: undefined,
    _filterPatterns: [],
    _disabledPlugins: new Set<string>(),
    _graphData: { nodes: [], edges: [] },
    _rawGraphData: { nodes: [], edges: [] },
    _firstAnalysis: true,
    _resolveFirstWorkspaceReady: vi.fn(),
    _sendMessage: vi.fn(),
    _sendDepthState: vi.fn(),
    _computeMergedGroups: vi.fn(),
    _sendGroupsUpdated: vi.fn(),
    _updateViewContext: vi.fn(),
    _applyViewTransform: vi.fn(),
    _sendPluginStatuses: vi.fn(),
    _sendDecorations: vi.fn(),
    _sendContextMenuItems: vi.fn(),
    ...overrides,
  };
}

describe('graphView/provider/analysis/methods', () => {
  it('returns analysis helpers without mutating the provider source', () => {
    const source = createSource();
    const methods = createGraphViewProviderAnalysisMethods(source as never, {
      runAnalysisRequest: vi.fn(async () => undefined),
      executeAnalysis: vi.fn(async () => undefined),
      markWorkspaceReady: vi.fn(),
      isAnalysisStale: vi.fn(() => false),
      isAbortError: vi.fn(() => false),
      hasWorkspace: vi.fn(() => true),
      logError: vi.fn(),
    });

    expect(methods._analyzeAndSendData).toEqual(expect.any(Function));
    expect(methods._doAnalyzeAndSendData).toEqual(expect.any(Function));
    expect(methods._markWorkspaceReady).toEqual(expect.any(Function));
    expect(methods._isAnalysisStale).toEqual(expect.any(Function));
    expect(methods._isAbortError).toEqual(expect.any(Function));
    expect(source._analyzeAndSendData).toBeUndefined();
    expect(source._doAnalyzeAndSendData).toBeUndefined();
    expect(source._markWorkspaceReady).toBeUndefined();
    expect(source._isAnalysisStale).toBeUndefined();
    expect(source._isAbortError).toBeUndefined();
  });

  it('marks workspace readiness with the current registry and syncs the live state back to the source', () => {
    const source = createSource();
    const graphData = {
      nodes: [{ id: 'graph-node', label: 'graph-node', color: '#ffffff' }],
      edges: [],
    } satisfies IGraphData;
    const markWorkspaceReady = vi.fn((state, registry, graph) => {
      expect(state.firstAnalysis).toBe(true);
      expect(state.resolveFirstWorkspaceReady).toBe(source._resolveFirstWorkspaceReady);
      expect(registry).toBe(source._analyzer?.registry);
      expect(graph).toBe(graphData);
      state.firstAnalysis = false;
      state.resolveFirstWorkspaceReady = undefined;
    });
    const methods = createGraphViewProviderAnalysisMethods(source as never, {
      runAnalysisRequest: vi.fn(async () => undefined),
      executeAnalysis: vi.fn(async () => undefined),
      markWorkspaceReady,
      isAnalysisStale: vi.fn(() => false),
      isAbortError: vi.fn(() => false),
      hasWorkspace: vi.fn(() => true),
      logError: vi.fn(),
    });

    methods._markWorkspaceReady(graphData);

    expect(markWorkspaceReady).toHaveBeenCalledOnce();
    expect(source._firstAnalysis).toBe(false);
    expect(source._resolveFirstWorkspaceReady).toBeUndefined();
  });

  it('passes live wrapper methods into the delegate factory', () => {
    const source = createSource({
      _analyzer: undefined,
    });
    const graphData = {
      nodes: [{ id: 'graph-node', label: 'graph-node', color: '#ffffff' }],
      edges: [],
    } satisfies IGraphData;
    const signal = new AbortController().signal;
    const error = new Error('aborted');
    const markWorkspaceReady = vi.fn((state, registry, graph) => {
      expect(registry).toBeUndefined();
      expect(graph).toBe(graphData);
      state.firstAnalysis = false;
      state.resolveFirstWorkspaceReady = undefined;
    });
    const isAnalysisStale = vi.fn((nextSignal, requestId, currentRequestId) =>
      nextSignal === signal && requestId === 5 && currentRequestId === 7,
    );
    const isAbortError = vi.fn(nextError => nextError === error);

    createGraphViewProviderAnalysisMethods(source as never, {
      runAnalysisRequest: vi.fn(async () => undefined),
      executeAnalysis: vi.fn(async () => undefined),
      markWorkspaceReady,
      isAnalysisStale,
      isAbortError,
      hasWorkspace: vi.fn(() => true),
      logError: vi.fn(),
    });

    const wrappers = vi.mocked(createGraphViewProviderAnalysisDelegates).mock.calls.at(-1)?.[1] as {
      markWorkspaceReady(graph: IGraphData): void;
      isAnalysisStale(signal: AbortSignal, requestId: number): boolean;
      isAbortError(error: unknown): boolean;
    };

    wrappers.markWorkspaceReady(graphData);

    expect(wrappers.isAnalysisStale(signal, 5)).toBe(true);
    expect(wrappers.isAbortError(error)).toBe(true);
    expect(markWorkspaceReady).toHaveBeenCalledOnce();
    expect(isAnalysisStale).toHaveBeenCalledWith(signal, 5, 7);
    expect(isAbortError).toHaveBeenCalledWith(error);
    expect(source._firstAnalysis).toBe(false);
    expect(source._resolveFirstWorkspaceReady).toBeUndefined();
  });

  it('checks analysis staleness against the current request id and delegates abort checks', () => {
    const signal = new AbortController().signal;
    const error = new Error('aborted');
    const isAnalysisStale = vi.fn((nextSignal, requestId, currentRequestId) =>
      nextSignal === signal && requestId === 3 && currentRequestId === 7,
    );
    const isAbortError = vi.fn(nextError => nextError === error);
    const methods = createGraphViewProviderAnalysisMethods(createSource() as never, {
      runAnalysisRequest: vi.fn(async () => undefined),
      executeAnalysis: vi.fn(async () => undefined),
      markWorkspaceReady: vi.fn(),
      isAnalysisStale,
      isAbortError,
      hasWorkspace: vi.fn(() => true),
      logError: vi.fn(),
    });

    expect(methods._isAnalysisStale(signal, 3)).toBe(true);
    expect(methods._isAbortError(error)).toBe(true);
    expect(isAnalysisStale).toHaveBeenCalledWith(signal, 3, 7);
    expect(isAbortError).toHaveBeenCalledWith(error);
  });

  it('wires delegate callbacks through executeAnalysis and runAnalysisRequest', async () => {
    const source = createSource();
    const signal = new AbortController().signal;
    const graphData = {
      nodes: [{ id: 'graph-node', label: 'graph-node', color: '#ffffff' }],
      edges: [],
    } satisfies IGraphData;
    const error = new Error('aborted');
    const markWorkspaceReady = vi.fn((state, _registry, graph) => {
      expect(graph).toBe(graphData);
      state.firstAnalysis = false;
      state.resolveFirstWorkspaceReady = undefined;
    });
    const isAnalysisStale = vi.fn((nextSignal, requestId, currentRequestId) =>
      nextSignal === signal && requestId === 11 && currentRequestId === 7,
    );
    const isAbortError = vi.fn(nextError => nextError === error);
    const executeAnalysis = vi.fn(async (_signal, _requestId, _state, handlers) => {
      expect(handlers.isAnalysisStale(signal, 11)).toBe(true);
      handlers.markWorkspaceReady(graphData);
      expect(handlers.isAbortError(error)).toBe(true);
    });
    const runAnalysisRequest = vi.fn(async (_state, handlers) => {
      await handlers.executeAnalysis(signal, 11);
      expect(handlers.isAbortError(error)).toBe(true);
    });
    const methods = createGraphViewProviderAnalysisMethods(source as never, {
      runAnalysisRequest,
      executeAnalysis,
      markWorkspaceReady,
      isAnalysisStale,
      isAbortError,
      hasWorkspace: vi.fn(() => true),
      logError: vi.fn(),
    });

    await methods._analyzeAndSendData();
    await methods._doAnalyzeAndSendData(signal, 11);

    expect(runAnalysisRequest).toHaveBeenCalledOnce();
    expect(executeAnalysis).toHaveBeenCalledTimes(2);
    expect(markWorkspaceReady).toHaveBeenCalledTimes(2);
    expect(isAnalysisStale).toHaveBeenCalledWith(signal, 11, 7);
    expect(isAbortError).toHaveBeenCalledWith(error);
    expect(source._firstAnalysis).toBe(false);
    expect(source._resolveFirstWorkspaceReady).toBeUndefined();
  });

  it('falls back to the delegate wrappers when source-owned analysis methods are unavailable', async () => {
    const source = createSource({
      _analyzer: undefined,
    });
    const signal = new AbortController().signal;
    const graphData = {
      nodes: [{ id: 'graph-node', label: 'graph-node', color: '#ffffff' }],
      edges: [],
    } satisfies IGraphData;
    const error = new Error('aborted');
    const markWorkspaceReady = vi.fn((state, registry, graph) => {
      expect(registry).toBeUndefined();
      expect(graph).toBe(graphData);
      state.firstAnalysis = false;
      state.resolveFirstWorkspaceReady = undefined;
    });
    const isAnalysisStale = vi.fn((nextSignal, requestId, currentRequestId) =>
      nextSignal === signal && requestId === 13 && currentRequestId === 7,
    );
    const isAbortError = vi.fn(nextError => nextError === error);
    const executeAnalysis = vi.fn(async (_signal, _requestId, _state, handlers) => {
      expect(handlers.isAnalysisStale(signal, 13)).toBe(true);
      handlers.markWorkspaceReady(graphData);
      expect(handlers.isAbortError(error)).toBe(true);
    });
    const methods = createGraphViewProviderAnalysisMethods(source as never, {
      runAnalysisRequest: vi.fn(async () => undefined),
      executeAnalysis,
      markWorkspaceReady,
      isAnalysisStale,
      isAbortError,
      hasWorkspace: vi.fn(() => true),
      logError: vi.fn(),
    });

    source._markWorkspaceReady = undefined;
    source._isAnalysisStale = undefined;
    source._isAbortError = undefined;

    await methods._doAnalyzeAndSendData(signal, 13);

    expect(markWorkspaceReady).toHaveBeenCalledOnce();
    expect(isAnalysisStale).toHaveBeenCalledWith(signal, 13, 7);
    expect(isAbortError).toHaveBeenCalledWith(error);
    expect(source._firstAnalysis).toBe(false);
    expect(source._resolveFirstWorkspaceReady).toBeUndefined();
  });
});

import { describe, expect, it, vi } from 'vitest';
import type { IGraphData } from '../../../../../src/shared/graph/types';
import {
  createGraphViewProviderAnalysisState,
  createGraphViewProviderWorkspaceReadyState,
  setGraphViewProviderGraphData,
  setGraphViewProviderRawGraphData,
  syncGraphViewProviderAnalysisExecutionState,
  syncGraphViewProviderAnalysisState,
  syncGraphViewProviderWorkspaceReadyState,
} from '../../../../../src/extension/graphView/provider/analysis/state';
import type { GraphViewProviderAnalysisMethodsSource } from '../../../../../src/extension/graphView/provider/analysis/methods';

function createSource(
  overrides: Partial<GraphViewProviderAnalysisMethodsSource> = {},
): GraphViewProviderAnalysisMethodsSource {
  return {
    _analysisController: undefined,
    _analysisRequestId: 1,
    _analyzer: undefined,
    _analyzerInitialized: false,
    _analyzerInitPromise: undefined,
    _filterPatterns: ['src/**'],
    _disabledPlugins: new Set<string>(['plugin-a']),
    _graphData: { nodes: [], edges: [] } satisfies IGraphData,
    _rawGraphData: { nodes: [], edges: [] } satisfies IGraphData,
    _firstAnalysis: true,
    _resolveFirstWorkspaceReady: vi.fn(),
    _sendMessage: vi.fn(),
    _sendDepthState: vi.fn(),
    _computeMergedGroups: vi.fn(),
    _sendGroupsUpdated: vi.fn(),
    _updateViewContext: vi.fn(),
    _applyViewTransform: vi.fn(),
    _sendPluginStatuses: vi.fn(),
    _sendDecorations: vi.fn(),
    _sendContextMenuItems: vi.fn(),
    ...overrides,
  };
}

describe('graphView/provider/analysis/state', () => {
  it('creates and syncs the analysis request state', () => {
    const source = createSource({
      _analysisController: new AbortController(),
      _analysisRequestId: 2,
      _analyzerInitialized: true,
      _analyzerInitPromise: Promise.resolve(),
    });

    const state = createGraphViewProviderAnalysisState(source, 'analyze');
    state.analysisController = undefined;
    state.analysisRequestId = 7;

    syncGraphViewProviderAnalysisState(source, state);

    expect(source._analysisController).toBeUndefined();
    expect(source._analysisRequestId).toBe(7);
    expect(source._analyzerInitialized).toBe(true);
    expect(source._analyzerInitPromise).toBeInstanceOf(Promise);
  });

  it('exposes analyzer, filter, and disabled plugin state through the accessors', () => {
    const source = createSource({
      _analyzer: { initialize: vi.fn(async () => undefined) } as never,
      _analyzerInitPromise: Promise.resolve(),
    });
    const nextAnalyzer = { initialize: vi.fn(async () => undefined) } as never;
    const state = createGraphViewProviderAnalysisState(source, 'load');
    expect(state.mode).toBe('load');

    expect(state.analyzer).toBe(source._analyzer);
    expect(state.analyzerInitPromise).toBe(source._analyzerInitPromise);
    expect(state.filterPatterns).toEqual(['src/**']);
    expect([...state.disabledPlugins]).toEqual(['plugin-a']);

    state.analyzer = nextAnalyzer;
    state.filterPatterns = ['dist/**'];
    state.disabledPlugins = new Set<string>(['plugin-b']);

    expect(source._analyzer).toBe(nextAnalyzer);
    expect(source._filterPatterns).toEqual(['dist/**']);
    expect([...source._disabledPlugins]).toEqual(['plugin-b']);
  });

  it('syncs analysis request state from plain state snapshots', () => {
    const source = createSource();
    const analysisController = new AbortController();

    syncGraphViewProviderAnalysisState(
      source,
      {
        analysisController,
        analysisRequestId: 9,
        analyzer: source._analyzer,
        analyzerInitialized: source._analyzerInitialized,
        analyzerInitPromise: source._analyzerInitPromise,
        mode: 'analyze',
        filterPatterns: source._filterPatterns,
        disabledPlugins: source._disabledPlugins,
      } as never,
    );

    expect(source._analysisController).toBe(analysisController);
    expect(source._analysisRequestId).toBe(9);
  });

  it('syncs execution state updates from plain state snapshots', () => {
    const source = createSource();
    const analysisController = new AbortController();
    const analyzerInitPromise = Promise.resolve();

    syncGraphViewProviderAnalysisExecutionState(
      source,
      {
        analysisController,
        analysisRequestId: 9,
        analyzer: source._analyzer,
        analyzerInitialized: true,
        analyzerInitPromise,
        mode: 'analyze',
        filterPatterns: source._filterPatterns,
        disabledPlugins: source._disabledPlugins,
      } as never,
    );

    expect(source._analysisController).toBe(analysisController);
    expect(source._analysisRequestId).toBe(9);
    expect(source._analyzerInitialized).toBe(true);
    expect(source._analyzerInitPromise).toBe(analyzerInitPromise);
  });

  it('reflects analyzer initialization progress onto the provider source immediately', () => {
    const source = createSource();
    const state = createGraphViewProviderAnalysisState(source, 'analyze');
    const initializePromise = Promise.resolve();

    state.analyzerInitPromise = initializePromise;
    state.analyzerInitialized = true;

    expect(source._analyzerInitPromise).toBe(initializePromise);
    expect(source._analyzerInitialized).toBe(true);
  });

  it('creates and syncs the workspace-ready state', () => {
    const source = createSource();
    const state = createGraphViewProviderWorkspaceReadyState(source);
    state.firstAnalysis = false;
    state.resolveFirstWorkspaceReady = undefined;

    syncGraphViewProviderWorkspaceReadyState(source, state);

    expect(source._firstAnalysis).toBe(false);
    expect(source._resolveFirstWorkspaceReady).toBeUndefined();
  });

  it('updates raw and transformed graph data on the provider source', () => {
    const source = createSource();
    const rawGraph = {
      nodes: [{ id: 'raw', label: 'raw', color: '#ffffff' }],
      edges: [],
    } satisfies IGraphData;
    const graph = {
      nodes: [{ id: 'graph', label: 'graph', color: '#ffffff' }],
      edges: [],
    } satisfies IGraphData;

    setGraphViewProviderRawGraphData(source, rawGraph);
    setGraphViewProviderGraphData(source, graph);

    expect(source._rawGraphData).toEqual(rawGraph);
    expect(source._graphData).toEqual(graph);
  });
});

